export interface TelegramRichMessageDraft {
  markdown: string;
}

export function renderTelegramRichDraft(text: string): TelegramRichMessageDraft {
  return { markdown: text.replace(/\r\n/g, "\n") };
}

export async function tryEditRichMessageDraft(
  api: unknown,
  chatId: number,
  messageId: number,
  text: string,
  extra: Record<string, unknown> = {},
): Promise<boolean> {
  const raw = (api as { raw?: { editMessageText?: unknown } }).raw;
  const method = raw?.editMessageText;
  if (typeof method !== "function") return false;
  const rich_message = renderTelegramRichDraft(text);
  await method.call(raw, {
    chat_id: chatId,
    message_id: messageId,
    ...extra,
    rich_message,
  });
  return true;
}

/**
 * Send a new rich message (for multi-chunk continuation messages).
 * Rich sends go through the dedicated Bot API 10.1 `sendRichMessage` method —
 * `sendMessage` ignores a `rich_message` param and delivers plain text.
 * Returns the sent message object, or undefined if rich send is unsupported
 * or rejected (caller falls back to a plain send).
 */
export async function trySendRichMessage(
  api: unknown,
  chatId: number,
  text: string,
  extra: Record<string, unknown> = {},
): Promise<{ message_id: number } | undefined> {
  const raw = (api as { raw?: { sendRichMessage?: unknown } }).raw;
  const method = raw?.sendRichMessage;
  if (typeof method !== "function") return undefined;
  const rich_message = renderTelegramRichDraft(text);
  try {
    const result = await method.call(raw, {
      chat_id: chatId,
      ...extra,
      rich_message,
    });
    return result as { message_id: number } | undefined;
  } catch {
    return undefined;
  }
}

